def start(host="0.0.0.0", port=80, path="/ws"):
    try:
        loop = asyncio.get_event_loop()
    except:
        loop = asyncio.new_event_loop()
        asyncio.set_event_loop(loop)
    loop.create_task(run_server(host=host, port=port, path=path))
    try:
        loop.run_forever()
    except KeyboardInterrupt:
        pass


# Optional: minimal WiFi connect helper
async def wifi_connect(ssid, password, timeout_s=15):
    if network is None:
        return False
    wlan = network.WLAN(network.STA_IF)
    if not wlan.active():
        wlan.active(True)
    if wlan.isconnected():
        return True
    wlan.connect(ssid, password)
    t0 = asyncio.get_event_loop().time()
    while not wlan.isconnected():
        if (asyncio.get_event_loop().time() - t0) > timeout_s:
            return False
        await asyncio.sleep(0.2)
    return True